import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

// The palette buttons only flip data-theme on the document root element; the SVG
// fills are var(--chart-*), so all three charts recolor via CSS with no JS
// color resolution and no chart re-render. Shared by the vanilla-js, React
// and Vue builds.
function setPalette(name) {
  document.documentElement.setAttribute('data-theme', name)
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Series A',
        data: [44, 55, 41, 67, 22, 43],
      },
      {
        name: 'Series B',
        data: [13, 23, 20, 8, 13, 27],
      },
      {
        name: 'Series C',
        data: [11, 17, 15, 15, 21, 14],
      },
    ],
    options: {
      chart: {
        id: 'cssVarBar',
        type: 'bar',
        height: 380,
        stacked: true,
      },
      colors: [
        'var(--chart-primary)',
        'var(--chart-secondary)',
        'var(--chart-tertiary)',
      ],
      fill: {
        opacity: 0.85,
      },
      plotOptions: {
        bar: {
          borderRadius: 4,
          borderRadiusApplication: 'end',
          borderRadiusWhenStacked: 'last',
          horizontal: false,
          columnWidth: '55%',
        },
      },
      dataLabels: {
        enabled: false,
      },
      xaxis: {
        categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
      },
      legend: {
        position: 'top',
      },
    },
    series1: [
      {
        name: 'Series A',
        data: [31, 40, 28, 51, 42, 109, 80],
      },
      {
        name: 'Series B',
        data: [11, 32, 45, 32, 34, 52, 41],
      },
      {
        name: 'Series C',
        data: [5, 18, 12, 26, 15, 31, 22],
      },
    ],
    options1: {
      chart: { id: 'cssVarArea', type: 'area', height: 350 },
      colors: [
        'var(--chart-primary)',
        'var(--chart-secondary)',
        'var(--chart-tertiary)',
      ],
      fill: { type: 'solid', opacity: 0.3 },
      stroke: { curve: 'smooth', width: 2 },
      dataLabels: { enabled: false },
      xaxis: { categories: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'] },
      legend: { position: 'top' },
    },
    series2: [44, 33, 23],
    options2: {
      chart: { id: 'cssVarDonut', type: 'donut', height: 350 },
      colors: [
        'var(--chart-primary)',
        'var(--chart-secondary)',
        'var(--chart-tertiary)',
      ],
      labels: ['Desktop', 'Tablet', 'Mobile'],
      fill: { opacity: 1 },
      legend: { position: 'bottom' },
    },
  })

  React.useEffect(() => {
    // The buttons live in the html block, so they are in the DOM when this effect
    // runs. setPalette lives in the shared head script; only CSS drives the
    // recolor, so no chart instance is needed here.
    const buttons = Array.from(document.querySelectorAll('.btn-color'))
    const handlers = buttons.map((btn) => {
      const handler = () => setPalette(btn.getAttribute('data-palette'))
      btn.addEventListener('click', handler)
      return handler
    })
    return () => {
      buttons.forEach((btn, i) => btn.removeEventListener('click', handlers[i]))
    }
  }, [])

  return (
    <div>
      <div className="controls">
        <button className="btn-color" data-palette="ocean">
          Ocean
        </button>
        <button className="btn-color" data-palette="sunset">
          Sunset
        </button>
        <button className="btn-color" data-palette="forest">
          Forest
        </button>
        <button className="btn-color" data-palette="neon">
          Neon
        </button>
        <button className="btn-color" data-palette="candy">
          Candy
        </button>
        <button className="btn-color" data-palette="arctic">
          Arctic
        </button>
      </div>

      <div className="info">
        This example uses <strong>CSS variables</strong> as chart colors. The
        SVG fill uses <code>var(--chart-primary)</code> directly — no JavaScript
        color resolution needed. Toggle the theme or change palettes to see the
        chart react instantly via CSS.
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="bar"
          height={380}
        />
      </div>
      <div id="chart2">
        <ReactApexChart
          options={state.options1}
          series={state.series1}
          type="area"
          height={350}
        />
      </div>
      <div id="chart3">
        <ReactApexChart
          options={state.options2}
          series={state.series2}
          type="donut"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart

:root,
[data-theme='default'] {
  --chart-primary: #008ffb;
  --chart-secondary: #00e396;
  --chart-tertiary: #feb019;
}

[data-theme='ocean'] {
  --chart-primary: #0077b6;
  --chart-secondary: #00b4d8;
  --chart-tertiary: #90e0ef;
}

[data-theme='sunset'] {
  --chart-primary: #e63946;
  --chart-secondary: #f4a261;
  --chart-tertiary: #e9c46a;
}

[data-theme='forest'] {
  --chart-primary: #2d6a4f;
  --chart-secondary: #52b788;
  --chart-tertiary: #95d5b2;
}

[data-theme='neon'] {
  --chart-primary: #9b5de5;
  --chart-secondary: #f15bb5;
  --chart-tertiary: #00f5d4;
}

[data-theme='candy'] {
  --chart-primary: #ff69b4;
  --chart-secondary: #ff85cb;
  --chart-tertiary: #ffc8dd;
}

[data-theme='arctic'] {
  --chart-primary: #4cc9f0;
  --chart-secondary: #4895ef;
  --chart-tertiary: #4361ee;
}

body {
  transition: background-color 0.3s;
}

.controls {
  max-width: 650px;
  margin: 20px auto 0;
  display: flex;
  gap: 12px;
  align-items: center;
  flex-wrap: wrap;
}

.controls button {
  padding: 8px 16px;
  border: none;
  border-radius: 6px;
  cursor: pointer;
  font-size: 14px;
  font-weight: 600;
  transition: 0.2s;
}

.btn-theme {
  background: #333;
  color: #fff;
}

.btn-theme:hover {
  background: #555;
}

.btn-color {
  color: #fff;
}

.btn-color[data-palette='ocean'] {
  background: #0077b6;
}
.btn-color[data-palette='sunset'] {
  background: #e63946;
}
.btn-color[data-palette='forest'] {
  background: #2d6a4f;
}
.btn-color[data-palette='neon'] {
  background: #9b5de5;
}
.btn-color[data-palette='candy'] {
  background: #ff69b4;
}
.btn-color[data-palette='arctic'] {
  background: #4cc9f0;
}

.info {
  max-width: 650px;
  margin: 12px auto;
  padding: 12px;
  background: #f0f4ff;
  border-radius: 6px;
  font-size: 13px;
  line-height: 1.5;
}

#chart,
#chart2,
#chart3 {
  max-width: 650px;
  margin: 35px auto;
  padding-top: 20px;
  padding-left: 10px;
  background: #fff;
  border: 1px solid #ddd;
  box-shadow: 0 22px 35px -16px rgba(0, 0, 0, 0.1);
}
